"use client";
import { useSession, signOut } from "next-auth/react";
import { useState } from "react";
import axios from "axios";

export default function Dashboard() {
  const { data: session } = useSession();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  const handleScan = async () => {
    // CHANGE THIS to your repo!
    const repoName = "aman-mishra/test-repo"; 
    
    setLoading(true);
    setMessage(`🚀 Scanning ${repoName}...`);

    try {
      const res = await axios.post("/api/scan", { repo_full_name: repoName });
      setMessage(`✅ Success: ${res.data.message}`);
    } catch (e: any) {
      console.error(e);
      setMessage(`❌ Error: ${e.response?.data?.error || e.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white p-10">
      <div className="flex justify-between mb-10">
        <h1 className="text-2xl font-bold">GitHelix Dashboard</h1>
        <button onClick={() => signOut()} className="text-red-400">Sign Out</button>
      </div>

      <div className="bg-gray-800 p-8 rounded-xl border border-gray-700">
        <p className="mb-4 text-gray-400">Logged in as: {session?.user?.name}</p>
        
        <button
          onClick={handleScan}
          disabled={loading}
          className="w-full py-4 bg-blue-600 hover:bg-blue-500 rounded-lg font-bold"
        >
          {loading ? "Scanning..." : "⚡ Scan Repository"}
        </button>

        {message && (
          <div className="mt-4 p-4 bg-black/50 border border-gray-600 rounded font-mono">
            {message}
          </div>
        )}
      </div>
    </div>
  );
}